import{c as i,Q as a,j as n,m as t}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"LangChain: Improving Deep Agents with Harness Engineering","description":"","frontmatter":{"url":"https://www.langchain.com/blog/improving-deep-agents-with-harness-engineering","date":"2026-05-09T00:00:00.000Z","authors":"LangChain Team","source":"LangChain Official Blog","tags":["harness-engineering","reasoning-sandwich","middleware-hooks","Terminal-Bench","+13.7-points"]},"headers":[],"relativePath":"research/ai-articles/scored/2026-05-09-langchain-deep-agents-harness-engineering.md","filePath":"research/ai-articles/scored/2026-05-09-langchain-deep-agents-harness-engineering.md","lastUpdated":1779894392000}'),r={name:"research/ai-articles/scored/2026-05-09-langchain-deep-agents-harness-engineering.md"};function l(o,e,s,d,h,c){return a(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="langchain-improving-deep-agents-with-harness-engineering" tabindex="-1">LangChain: Improving Deep Agents with Harness Engineering <a class="header-anchor" href="#langchain-improving-deep-agents-with-harness-engineering" aria-label="Permalink to &quot;LangChain: Improving Deep Agents with Harness Engineering&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://www.langchain.com/blog/improving-deep-agents-with-harness-engineering" target="_blank" rel="noreferrer">https://www.langchain.com/blog/improving-deep-agents-with-harness-engineering</a><br><strong>作者</strong>：LangChain Team<br><strong>歸檔日期</strong>：2026-05-09</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>LangChain 在 Terminal-Bench 2.0 上達成 <strong>13.7 百分點的改進</strong>（52.8% → 66.5%）仅通過改變 harness，模型保持不變（GPT-5.2-Codex）。核心技術：「reasoning sandwich」（plan with xhigh、implement with high、verify with xhigh）、middleware hooks（LocalContextMiddleware、PreCompletionChecklistMiddleware、LoopDetectionMiddleware）。</p><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><ol><li><p><strong>Harness = System Prompts + Tools + Middleware</strong></p><ul><li>三個可獨立操作的 harness 層</li><li>發現：Harness 對 benchmark 分數的影響力 = 或 &gt; 模型升級</li></ul></li><li><p><strong>Reasoning Sandwich：非線性 Reasoning 配置</strong></p><ul><li>Naive xhigh everywhere = 53.9%（超時）</li><li>High only = 63.6%</li><li>xhigh (plan) + high (implement) + xhigh (verify) = 66.5%</li><li>Insight：不同任務階段的 reasoning 需求不對稱</li></ul></li><li><p><strong>Middleware 攔截點的力量</strong></p><ul><li><code>LocalContextMiddleware</code>：預先掃描 dir 結構、available tools、Python 版本 → inject</li><li><code>PreCompletionChecklistMiddleware</code>：強制驗證通過後才退出</li><li><code>LoopDetectionMiddleware</code>：追蹤重複編輯以避免「doom loop」</li><li>這些都是「模型無法獨立完成」的假設編碼</li></ul></li><li><p><strong>Trace-Driven 迭代而非猜測</strong></p><ul><li>分析失敗的 trace 找出真實瓶頸</li><li>而非「覺得應該改這個」的投機優化</li><li>每輪改動量化結果</li></ul></li></ol><hr><h2 id="直接意涵" tabindex="-1">直接意涵 <a class="header-anchor" href="#直接意涵" aria-label="Permalink to &quot;直接意涵&quot;">​</a></h2><h3 id="cc-workspace-可行動性" tabindex="-1">cc-workspace 可行動性 <a class="header-anchor" href="#cc-workspace-可行動性" aria-label="Permalink to &quot;cc-workspace 可行動性&quot;">​</a></h3><ol><li><p><strong>Reasoning Sandwich 套用到 Opus Pilot Mode</strong></p><ul><li>當前 <code>.claude/refs/opus-pilot/SKILL.md</code> 使用「xhigh」作單純選項</li><li>LangChain 的發現表示：應該探索「plan 階段用 xhigh、refactor/implement 階段用 high」的混合策略</li><li>適合補充進 <code>.claude/skills/opus-pilot/prompt.md</code> 作為推薦配置</li></ul></li><li><p><strong>Middleware Hooks 架構在 cc-workspace 中的應用</strong></p><ul><li>推文 @nicbstme 提及 Codex 的 <code>Phase 2 consolidation prompt</code>、Claude Code 的 <code>&lt;system-reminder&gt;</code> 都是 middleware 的例子</li><li>cc-workspace 當前有 <code>PreCompletionChecklistMiddleware</code> 的等效物嗎？（TodoWrite + verification step）</li><li><code>.claude/rules/core.md</code> 提到「驗證指令」（healthcheck），可視為 pre-exit middleware</li></ul></li><li><p><strong>上下文準備的 ROI</strong></p><ul><li>LocalContextMiddleware 減少模型理解工作環境的成本</li><li>cc-workspace 的 <code>~/.claude/projects/&lt;cwd&gt;/memory/</code> 是類似機制（預載入歷史脈絡）</li><li>Insight：harness 應主動「塞進」模型需要的環境信號，而非期待模型自行發現</li></ul></li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>9/10</td><td>Reasoning sandwich 可直接套用；middleware pattern 符合 cc-workspace hook 設計；量化數據強</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>推理預算分配不新奇，但「per-phase reasoning effort」系統化程度高</td></tr><tr><td>C. 證據品質</td><td>9/10</td><td>Terminal-Bench 排行驗證（Top 30→Top 5）；逐步改進的數據清晰（52.8→66.5）</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>Middleware 架構清晰；缺乏 ablation study（各元件獨立貢獻多少）</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>Reasoning sandwich 適用任何 reasoning-capable 模型；middleware pattern 跨 agent 框架通用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.2/10</strong></td><td>9×0.3 + 7×0.2 + 9×0.2 + 8×0.15 + 8×0.15 = 2.7+1.4+1.8+1.2+1.2 = 8.3</td></tr></tbody></table><p><strong>整合決策</strong>：Skill（補充進 <code>.claude/skills/opus-pilot/prompt.md</code> 或新增 <code>.claude/skills/reasoning-sandwich/prompt.md</code>）</p><hr><h2 id="引用關聯" tabindex="-1">引用關聯 <a class="header-anchor" href="#引用關聯" aria-label="Permalink to &quot;引用關聯&quot;">​</a></h2><ul><li>推文 @nicbstme 2026-05-04：「LangChain Opus 4.6 在不同 harness 分數差異」引用</li><li><code>.claude/skills/opus-pilot/SKILL.md</code>：推理預算配置</li><li><code>.claude/rules/core.md</code>：驗證指令與 pre-exit middleware</li><li>Terminal-Bench 2.0：排行驗證基準</li></ul>',19)])])}const m=i(r,[["render",l]]);export{p as __pageData,m as default};
